import React, { useState } from "react";
import { predict } from "../services/api";

export default function PredictionPanel({
  trainedResults,
  onNotify,
}) {
  const [inputs, setInputs] = useState({});
  const [modelId, setModelId] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const modelIds = Object.keys(
    trainedResults || {}
  );

  const activeId = modelId || modelIds[0];

  const set = (key, value) =>
    setInputs((prev) => ({
      ...prev,
      [key]: parseFloat(value) || 0,
    }));

  const handlePredict = async () => {
    if (!activeId) {
      onNotify(
        "⚠️ Aucun modèle entraîné",
        "warning"
      );

      return;
    }

    setLoading(true);

    try {
      const res = await predict({
        model_id: activeId,
        features: inputs,
      });

      setResult(res);
    } catch (err) {
      onNotify(
        "❌ Erreur prédiction",
        "error"
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-white/60 backdrop-blur-2xl border border-white/40 rounded-[32px] p-8 shadow-[0_8px_40px_rgba(0,0,0,0.08)] space-y-6">

      {/* HEADER */}
      <div>
        <h2 className="text-3xl font-black bg-gradient-to-r from-cyan-600 via-blue-600 to-purple-600 bg-clip-text text-transparent">
          🔮 Prediction Panel
        </h2>

        <p className="text-slate-500 mt-2">
          Predict outcomes using trained machine learning models
        </p>
      </div>

      {/* MODEL SELECTOR */}
      <div className="space-y-2">

        <label className="text-sm font-bold text-slate-700">
          Select Model
        </label>

        <select
          value={activeId || ""}
          onChange={(e) =>
            setModelId(e.target.value)
          }
          className="w-full bg-white/80 border border-slate-200 rounded-2xl px-5 py-4 text-slate-700 font-semibold shadow-sm focus:outline-none focus:ring-4 focus:ring-cyan-200 transition-all"
        >
          <option value="">
            Select model
          </option>

          {modelIds.map((id) => (
            <option
              key={id}
              value={id}
            >
              {id}
            </option>
          ))}
        </select>
      </div>

      {/* FEATURE INPUT */}
      <div className="space-y-2">

        <label className="text-sm font-bold text-slate-700">
          Feature Value
        </label>

        <input
          placeholder="Enter feature value..."
          onChange={(e) =>
            set("test", e.target.value)
          }
          className="w-full bg-white/80 border border-slate-200 rounded-2xl px-5 py-4 text-slate-700 shadow-sm focus:outline-none focus:ring-4 focus:ring-blue-200 transition-all"
        />
      </div>

      {/* PREDICT BUTTON */}
      <button
        onClick={handlePredict}
        disabled={loading}
        className="w-full py-4 rounded-3xl bg-gradient-to-r from-cyan-500 via-blue-500 to-purple-500 text-white text-lg font-black shadow-[0_10px_40px_rgba(59,130,246,0.35)] hover:scale-[1.02] transition-all duration-300 disabled:opacity-50"
      >
        {loading ? (
          <div className="flex items-center justify-center gap-3">

            <svg
              className="animate-spin h-5 w-5"
              viewBox="0 0 24 24"
              fill="none"
            >
              <circle
                cx="12"
                cy="12"
                r="10"
                stroke="currentColor"
                strokeOpacity="0.3"
                strokeWidth="3"
              />

              <path
                d="M12 2a10 10 0 0 1 10 10"
                stroke="currentColor"
                strokeWidth="3"
                strokeLinecap="round"
              />
            </svg>

            Predicting...
          </div>
        ) : (
          "🚀 Run Prediction"
        )}
      </button>

      {/* RESULT */}
      {result && (
        <div className="bg-gradient-to-br from-cyan-50 to-blue-50 border border-cyan-200 rounded-3xl p-6 shadow-inner space-y-4">

          <h3 className="text-xl font-black text-slate-800">
            📊 Prediction Result
          </h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">

            {/* Prediction */}
            <div className="bg-white/80 rounded-2xl p-5 shadow-sm border border-white">

              <p className="text-sm text-slate-500 font-medium">
                Prediction
              </p>

              <p className="text-3xl font-black text-blue-600 mt-2">
                {result.prediction}
              </p>
            </div>

            {/* Risk */}
            <div className="bg-white/80 rounded-2xl p-5 shadow-sm border border-white">

              <p className="text-sm text-slate-500 font-medium">
                Risk Probability
              </p>

              <p className="text-3xl font-black text-emerald-600 mt-2">
                {result.risk_probability}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
